description:
Implement the built-in format style handlers for json, yaml, and toon. Critical: these must use pv.ty as the schema target, NOT parent format.

Location: crates/baml-bridge/src/prompt/renderer.rs

```rust
impl PromptWorld {
    /// Try built-in format style (json|yaml|toon)
    fn try_builtin_style(&self, pv: &PromptValue, style: &str) -> Result<Option<RenderOutput>, RenderError> {
        match style {
            'json' | 'yaml' | 'toon' => {
                let text = self.render_format_style(pv, style)?;
                Ok(Some(RenderOutput { text }))
            }
            _ => Ok(None),  // Not a builtin style
        }
    }

    /// Render using built-in format style with CORRECT schema target
    fn render_format_style(&self, pv: &PromptValue, fmt: &str) -> Result<String, RenderError> {
        // CRITICAL: Build OutputFormatContent view with pv.ty as target
        // This fixes the schema-target bug where nested types used wrong schema
        let view = self.build_output_format_view(&pv.ty);

        internal_baml_jinja::format_baml_value(&pv.value, &view, fmt)
            .map_err(|e| RenderError {
                path: pv.path.to_string(),
                ty: pv.ty.diagnostic_repr().to_string(),
                style: fmt.to_string(),
                renderer: format\!('builtin:{}', fmt),
                template_name: None,
                template_location: None,
                message: format\!('format style render failed: {}', e),
                cause: Some(Box::new(e)),
            })
    }

    /// Build OutputFormatContent view for a specific type target
    fn build_output_format_view(&self, ty: &TypeIR) -> OutputFormatContent {
        OutputFormatContent {
            enums: self.types.enums.clone(),
            classes: self.types.classes.clone(),
            recursive_classes: self.types.recursive_classes.clone(),
            structural_recursive_aliases: self.types.structural_recursive_aliases.clone(),
            target: ty.clone(),  // THE KEY FIX
        }
    }
}
```

This is the 'wrong schema context' fix from the spec. When rendering a nested type like value.history.render('json'), the schema must be for history's type, not the top-level input type.
